import { useEffect, useState } from "react";
import { breakpoints } from "@angi/one-design-system-tokens";

/**
 * Breakpoint keys from the design system tokens.
 */
export type Breakpoint = keyof typeof breakpoints;

/**
 * Ordered list of breakpoints from smallest to largest.
 * Dynamically sorted by parsing the rem values from the tokens.
 */
const BREAKPOINTS_ORDERED = (
  Object.entries(breakpoints) as [Breakpoint, string][]
)
  .sort(([, a], [, b]) => parseFloat(a) - parseFloat(b))
  .map(([key]) => key);

/**
 * Hook that returns a value based on the current screen width and breakpoint configuration.
 *
 * Uses a mobile-first approach: returns the value associated with the largest breakpoint
 * that is smaller than or equal to the current screen width. If no breakpoints match,
 * returns the default value.
 *
 * @param defaultValue - The value to return when no breakpoints match
 * @param config - Partial mapping of breakpoints to values
 * @returns The value for the current screen width
 *
 * @example
 * ```tsx
 * const columns = useResponsiveProp(1, { sm: 2, lg: 4 });
 * // Returns 1 on screens < 40rem
 * // Returns 2 on screens >= 40rem and < 64rem
 * // Returns 4 on screens >= 64rem
 * ```
 *
 * @note This hook relies on browser APIs to measure screen width. During SSR, it always
 * returns the `defaultValue`. After hydration, it will update to the appropriate value
 * based on the current screen width. This can cause layout shifts for content that is
 * immediately visible above the fold. For layout-critical responsive behavior, prefer
 * CSS-based solutions over this hook.
 */
export function useResponsiveProp<T>(
  defaultValue: T,
  config: Partial<Record<Breakpoint, T>>
): T {
  const [value, setValue] = useState<T>(defaultValue);

  // Serialize config to get a stable dependency for the effect.
  const configKey = JSON.stringify(config);

  useEffect(() => {
    // Get breakpoints that are configured (with non-undefined values), in order from smallest to largest
    const configuredBreakpoints = BREAKPOINTS_ORDERED.filter(
      (bp) => bp in config && config[bp] !== undefined
    );

    if (configuredBreakpoints.length === 0) {
      setValue(defaultValue);
      return;
    }

    // Create media query lists for each configured breakpoint
    const mediaQueryLists = configuredBreakpoints.map((bp) => ({
      breakpoint: bp,
      mql: window.matchMedia(`(min-width: ${breakpoints[bp]})`),
    }));

    const updateValue = () => {
      // Find the largest matching breakpoint (iterate in reverse order)
      let matchedValue: T = defaultValue;

      for (const { breakpoint, mql } of mediaQueryLists) {
        if (mql.matches) {
          matchedValue = config[breakpoint] as T;
        }
      }

      setValue(matchedValue);
    };

    // Set initial value
    updateValue();

    // Add listeners for each media query
    for (const { mql } of mediaQueryLists) {
      mql.addEventListener("change", updateValue);
    }

    // Cleanup listeners
    return () => {
      for (const { mql } of mediaQueryLists) {
        mql.removeEventListener("change", updateValue);
      }
    };
  }, [defaultValue, configKey]);

  return value;
}
